  awk -F'\t' -v f="V;$feat" '$3==f {
    lem=$1; inf=$2;
    # determine prefix relationship
    if (inf==lem) rel="NONE";
    else if (substr(inf,2)==lem) rel="+"substr(inf,1,1);
    else rel="OTHER:"lem"->"inf;
    print rel
  }' mlg.trn | sort | uniq -c
done

